/*
 * powf() test harness — prints (input_hex, output_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly powf  (test_powf_opt.elf)
 *   2. Linked with toolchain's default powf        (test_powf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x, float y)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    volatile float vy = y;
    g_acc += powf(vx, vy);
#else
    float r = powf(x, y);
    printf("%08lx %08lx %08lx\n",
           (unsigned long)f2u(x), (unsigned long)f2u(y), (unsigned long)f2u(r));
#endif
}

#ifndef EN_PERF
static void emit_u(uint32_t bx, uint32_t by)
{
    emit(u2f(bx), u2f(by));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 combos (15) --- */
    emit(0.0f,  0.0f);                             /* 0^0 = 1 by convention */
    emit(-0.0f, 0.0f);                             /* -0^0 = 1 by convention */
    emit(0.0f,  2.0f);                             /* 0^positive = 0 */
    emit(0.0f, -1.0f);                             /* 0^negative = +Inf */
    emit(-0.0f, -1.0f);                            /* -0^negative-odd = -Inf */
    emit(-0.0f,  3.0f);                            /* -0^positive-odd = -0 */
    emit_u(0x7f800000u, 0x40000000u);              /* +Inf ^ 2 = +Inf */
    emit_u(0xff800000u, 0x40000000u);              /* -Inf ^ 2 = +Inf */
    emit_u(0xff800000u, 0x3f800000u);              /* -Inf ^ 1 = -Inf (odd) */
    emit_u(0x7f800000u, 0x00000000u);              /* +Inf ^ 0 = 1 */
    emit_u(0x7fc00000u, 0x3f800000u);              /* qNaN ^ 1 = NaN */
    emit_u(0x3f800000u, 0x7fc00000u);              /* 1 ^ qNaN = NaN (or 1) */
    emit_u(0x7f800000u, 0x7f800000u);              /* +Inf ^ +Inf = +Inf */
    emit_u(0x7f800000u, 0xff800000u);              /* +Inf ^ -Inf = 0 */
    emit_u(0xff800000u, 0xff800000u);              /* -Inf ^ -Inf = 0 */

    /* --- Section 2: Negative base with non-integer exponent -> NaN (7) --- */
    emit(-1.0f,  0.5f);                            /* (-1)^0.5 = NaN */
    emit(-2.0f,  0.5f);                            /* (-2)^0.5 = NaN */
    emit(-0.5f,  0.5f);                            /* (-0.5)^0.5 = NaN */
    emit(-4.0f,  1.5f);                            /* (-4)^1.5 = NaN */
    emit_u(0xbf800000u, 0x3fc90fdbu);              /* -1 ^ (pi/2) = NaN */
    emit_u(0xc0000000u, 0x3f317218u);              /* -2 ^ ln2 = NaN */
    emit(-FLT_MIN,  2.5f);                         /* -FLT_MIN ^ 2.5 = NaN */

    /* --- Section 3: Subnormal bases (6) --- */
    emit_u(0x00000001u, 0x3f800000u);              /* min positive subnormal ^ 1 */
    emit_u(0x00000001u, 0x40000000u);              /* min positive subnormal ^ 2 */
    emit_u(0x00400000u, 0x40000000u);              /* mid subnormal ^ 2 */
    emit_u(0x007fffffu, 0x3f800000u);              /* max subnormal (just below FLT_MIN) ^ 1 */
    emit_u(0x007fffffu, 0x40000000u);              /* max subnormal ^ 2 */
    emit_u(0x00400000u, 0x3f000000u);              /* mid subnormal ^ 0.5 */

    /* --- Section 4: Near base=1.0 ULP neighbors (8) --- */
    emit_u(0x3f7fffffu, 0x40000000u);              /* one ULP below 1.0, exp=2 */
    emit(1.0f,   2.0f);                            /* 1^2 = 1 */
    emit_u(0x3f800001u, 0x40000000u);              /* one ULP above 1.0, exp=2 */
    emit_u(0x3f7ffff0u, 0x40490fdbu);              /* a few ULPs below 1.0, exp=pi */
    emit_u(0x3f800010u, 0x40490fdbu);              /* a few ULPs above 1.0, exp=pi */
    emit(1.0f, 1000.0f);                           /* 1^large = 1 */
    emit_u(0x3f7fffffu, 0x4b800000u);              /* just-below-1 ^ 1e7 */
    emit_u(0x3f800001u, 0x4b800000u);              /* just-above-1 ^ 1e7 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3effffffu, 0x40000000u);              /* one ULP below 0.5, exp=2 */
    emit(0.5f, 2.0f);                              /* 0.5^2 = 0.25 */
    emit_u(0x3f000001u, 0x40000000u);              /* one ULP above 0.5, exp=2 */
    emit_u(0x3fffffffu, 0x40000000u);              /* one ULP below 2.0, exp=2 */
    emit(2.0f, 2.0f);                              /* 2^2 = 4 */
    emit_u(0x40000001u, 0x40000000u);              /* one ULP above 2.0, exp=2 */

    /* --- Section 6: Pow-specific mathematical constants (14) --- */
    emit(2.0f,   0.5f);                            /* sqrt(2) */
    emit(2.0f,  -0.5f);                            /* 1/sqrt(2) */
    emit(2.0f,  10.0f);                            /* 1024 */
    emit(2.0f, -10.0f);                            /* 1/1024 */
    emit(0.5f,  10.0f);                            /* 2^-10 */
    emit(10.0f,  3.0f);                            /* 1000 */
    emit(10.0f, -3.0f);                            /* 0.001 */
    emit_u(0x402df854u, 0x3f800000u);              /* e^1 = e */
    emit_u(0x402df854u, 0x40000000u);              /* e^2 */
    emit_u(0x3f317218u, 0x3f800000u);              /* ln2 ^ 1 */
    emit(4.0f,   0.5f);                            /* sqrt(4) = 2 exact */
    emit(9.0f,   0.5f);                            /* sqrt(9) = 3 exact */
    emit(0.25f,  0.5f);                            /* sqrt(0.25) = 0.5 exact */
    emit(8.0f,   u2f(0x3f2aaaab));                 /* 8^(1/3) = 2 (cube root) */

    /* --- Section 7: Overflow and underflow thresholds (8) --- */
    emit(2.0f,   127.0f);                          /* 2^127, near FLT_MAX */
    emit(2.0f,   128.0f);                          /* 2^128, overflows */
    emit(2.0f,  -126.0f);                          /* 2^-126 = FLT_MIN */
    emit(2.0f,  -149.0f);                          /* 2^-149 = min subnormal */
    emit(2.0f,  -150.0f);                          /* 2^-150, underflows to 0 */
    emit_u(0x7f7fffffu, 0x40000000u);              /* FLT_MAX ^ 2 = +Inf */
    emit_u(0x7f7fffffu, 0x3f000000u);              /* FLT_MAX ^ 0.5 */
    emit_u(0x00800000u, 0x40000000u);              /* FLT_MIN ^ 2 (subnormal result) */

    /* --- Section 8: Negative base with integer exponents (14) --- */
    emit(-1.0f,  0.0f);                            /* -1^0 = 1 */
    emit(-1.0f,  1.0f);                            /* -1^1 = -1 */
    emit(-1.0f,  2.0f);                            /* -1^2 = 1 */
    emit(-1.0f,  3.0f);                            /* -1^3 = -1 */
    emit(-1.0f, -1.0f);                            /* -1^-1 = -1 */
    emit(-1.0f, -2.0f);                            /* -1^-2 = 1 */
    emit(-2.0f,  1.0f);                            /* -2^1 = -2 */
    emit(-2.0f,  2.0f);                            /* -2^2 = 4 */
    emit(-2.0f,  3.0f);                            /* -2^3 = -8 */
    emit(-2.0f, -1.0f);                            /* -2^-1 = -0.5 */
    emit(-2.0f, -2.0f);                            /* -2^-2 = 0.25 */
    emit(-10.0f,  2.0f);                           /* -10^2 = 100 */
    emit(-10.0f,  3.0f);                           /* -10^3 = -1000 */
    emit(-10.0f, -2.0f);                           /* -10^-2 = 0.01 */

    /* --- Section 9: Fractional exponent grid, base in (0,2] (12) --- */
    emit(0.125f,  0.5f);                           /* sqrt(0.125) */
    emit(0.25f,   2.0f);                           /* 0.0625 */
    emit(0.375f,  3.0f);                           /* 0.375^3 */
    emit(0.75f,   4.0f);                           /* 0.75^4 */
    emit(0.875f,  8.0f);                           /* 0.875^8 */
    emit(1.5f,    4.0f);                           /* 1.5^4 */
    emit(1.5f,   -2.0f);                           /* 1.5^-2 */
    emit(1.25f,   3.0f);                           /* 1.25^3 */
    emit(1.1f,   10.0f);                           /* 1.1^10 */
    emit(0.9f,   10.0f);                           /* 0.9^10 */
    emit(0.1f,    3.0f);                           /* 0.001 */
    emit(0.1f,   -2.0f);                           /* 100 */

    /* --- Section 10: IEEE spec special combos (10) --- */
    emit(1.0f,   u2f(0x7f800000u));                /* 1^+Inf = 1 */
    emit(1.0f,   u2f(0xff800000u));                /* 1^-Inf = 1 */
    emit(-1.0f,  u2f(0x7f800000u));                /* (-1)^+Inf = 1 */
    emit(-1.0f,  u2f(0xff800000u));                /* (-1)^-Inf = 1 */
    emit(0.5f,   u2f(0x7f800000u));                /* 0.5^+Inf = 0 */
    emit(0.5f,   u2f(0xff800000u));                /* 0.5^-Inf = +Inf */
    emit(2.0f,   u2f(0x7f800000u));                /* 2^+Inf = +Inf */
    emit(2.0f,   u2f(0xff800000u));                /* 2^-Inf = 0 */
    emit(0.0f,   u2f(0xff800000u));                /* 0^-Inf = +Inf */
    emit(0.0f,   u2f(0x7f800000u));                /* 0^+Inf = 0 */
}

/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                  */
/* ------------------------------------------------------------------ */

/* Sweep base [0.1, 10] with fixed exponent 2.0 */
static void test_sweep_base(void)
{
    float lo = 0.1f, hi = 10.0f;
    int nsteps = 100;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step, 2.0f);
}

/* Sweep exponent [0.5, 3.0] with base 2.0 */
static void test_sweep_exp(void)
{
    float lo = 0.5f, hi = 3.0f;
    int nsteps = 100;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(2.0f, lo + (float)i * step);
}

/* Random sweep: 15x20 grid = 300 cases */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        float x = 0.5f + 9.5f * (float)i / (float)(nx - 1);
        for (int j = 0; j < ny; j++) {
            float y = -3.0f + 6.0f * (float)j / (float)(ny - 1);
            emit(x, y);
        }
    }
}
#endif /* !EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep_base();
    test_sweep_exp();
    test_random_300();
#endif
    return 0;
}

